  1→import * as schema from "@rudel/sql-schema";
  2→import { betterAuth } from "better-auth";
  3→import { drizzleAdapter } from "better-auth/adapters/drizzle";
  4→import { bearer, organization } from "better-auth/plugins";
  5→import { fetchGitHubHandle, notifySignup } from "./slack.js";
  6→
  7→export interface AuthConfig {
  8→	appURL: string;
  9→	secret?: string;
 10→	socialProviders?: Record<string, { clientId: string; clientSecret: string }>;
 11→	trustedOrigins?: string[];
 12→	slackWebhookUrl?: string;
 13→}
 14→
 15→// eslint-disable-next-line @typescript-eslint/no-explicit-any -- drizzleAdapter accepts { [key: string]: any }
 16→export function createAuth(db: object, config: AuthConfig) {
 17→	const trustedOrigins = config.trustedOrigins ?? [];
 18→	if (!trustedOrigins.includes(config.appURL)) {
 19→		trustedOrigins.push(config.appURL);
 20→	}
 21→
 22→	return betterAuth({
 23→		baseURL: config.appURL,
 24→		secret: config.secret,
 25→		database: drizzleAdapter(db as Parameters<typeof drizzleAdapter>[0], {
 26→			provider: "pg",
 27→			schema,
 28→		}),
 29→		emailAndPassword: {
 30→			enabled: true,
 31→		},
 32→		socialProviders: config.socialProviders,
 33→		plugins: [
 34→			bearer(),
 35→			organization({
 36→				allowUserToCreateOrganization: true,
 37→				creatorRole: "owner",
 38→			}),
 39→		],
 40→		session: {
 41→			expiresIn: 60 * 60 * 24 * 365,
 42→		},
 43→		trustedOrigins,
 44→		databaseHooks: {
 45→			user: {
 46→				create: {
 47→					after: async (user, ctx) => {
 48→						try {
 49→							const adapter = ctx?.context?.adapter;
 50→							if (!adapter) return;
 51→
 52→							const slug = `${user.email.split("@")[0]}-${user.id.slice(0, 8)}`;
 53→							const org = await adapter.create({
 54→								model: "organization",
 55→								data: {
 56→									id: user.id,
 57→									name: `${user.name}'s Workspace`,
 58→									slug,
 59→									createdAt: new Date(),
 60→								},
 61→								forceAllowId: true,
 62→							});
 63→
 64→							if (org) {
 65→								await adapter.create({
 66→									model: "member",
 67→									data: {
 68→										organizationId: org.id,
 69→										userId: user.id,
 70→										role: "owner",
 71→										createdAt: new Date(),
 72→									},
 73→								});
 74→							}
 75→
 76→							if (config.slackWebhookUrl) {
 77→								let githubHandle: string | null = null;
 78→								const accounts = (await adapter.findMany({
 79→									model: "account",
 80→									where: [{ field: "userId", value: user.id }],
 81→								})) as Array<{ providerId: string; accountId: string }>;
 82→								const githubAccount = accounts.find(
 83→									(a) => a.providerId === "github",
 84→								);
 85→								if (githubAccount) {
 86→									githubHandle = await fetchGitHubHandle(
 87→										githubAccount.accountId,
 88→									);
 89→								}
 90→								await notifySignup(
 91→									config.slackWebhookUrl,
 92→									{ name: user.name, email: user.email },
 93→									githubHandle,
 94→								);
 95→							}
 96→						} catch (err) {
 97→							console.error(
 98→								"Failed to create default organization for user",
 99→								user.id,
100→								err,
101→							);
102→						}
103→					},
104→				},
105→			},
106→		},
107→	});
108→}
109→
110→export type Auth = ReturnType<typeof createAuth>;
111→export type Session = Auth["$Infer"]["Session"];
