import { afterAll, beforeAll, describe, expect, test } from "bun:test";
import type { IngestSessionInput } from "@rudel/api-routes";
import type { ClickHouseExecutor } from "../clickhouse.js";
import {
	buildSessionRow,
	extractTimestampRange,
	ingestSession,
} from "../ingest.js";

